import akka.actor._
import akka.http.scaladsl.{Http, HttpEntity}
import akka.stream.ActorMaterializer
import scala.concurrent.duration._
import scala.util.Try


object Main extends App {
  val port = 8091

  val system = ActorSystem("Main")
  val materializer = ActorMaterializer()

  val server = Http().bindAndHandle(
    handleRequest(system), "localhost", port)

  println(s"Server running at http://localhost:$port/")

  System.exit(0)
}


def handleRequest(system: ActorSystem): PartialFunction[HttpRequest, Future[HttpResponse]] = {
  case HttpRequest(uri) =>
    Http().singleRequest(HttpRequest(uri=uri))
      .map(response => response.entity.toStrict(5 seconds).value)
      .flatMap(Try(_).toOption.fold(
        err => Future.failed(err),
        entity => Future.successful(HttpResponse(entity = HttpEntity.Strict(entity)))
      ))
}